ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?title ?production_cost WHERE {
  ?films a :Films .
  ?films p:title ?title .
  ?films p:Production_Cost ?production_cost .
  ?films p:Production_Cost ?production_cost_o .
}
ORDER BY ASC(?production_cost_o) }
  component_2: { SELECT ?title ?marketing_expense WHERE {
  ?films a :Films .
  ?films p:title ?title .
  ?films p:Marketing_Expense ?marketing_expense .
  ?films p:Marketing_Expense ?marketing_expense_o .
}
ORDER BY ASC(?marketing_expense_o) }
  full: { SELECT ?title ?production_cost ?marketing_expense WHERE {
  ?films a :Films .
  ?films p:title ?title .
  ?films p:Production_Cost ?production_cost .
  ?films p:Marketing_Expense ?marketing_expense .
  ?films p:Production_Cost ?production_cost_o .
  ?films p:Marketing_Expense ?marketing_expense_o .
}
ORDER BY ASC(?production_cost_o) ASC(?marketing_expense_o) }
}

PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
CHOICE vague {
  full: { SELECT ?t ?pc ?me (COUNT(?aw) AS ?n) WHERE { ?aw a :Awards ; p:hasFilms ?f . ?f a :Films ; p:title ?t ; p:Production_Cost ?pc ; p:Marketing_Expense ?me } GROUP BY ?f ?t ?pc ?me }
  component: { SELECT ?t ?pc (COUNT(?aw) AS ?n) WHERE { ?aw a :Awards ; p:hasFilms ?f . ?f a :Films ; p:title ?t ; p:Production_Cost ?pc } GROUP BY ?f ?t ?pc }
  component_2: { SELECT ?t ?me (COUNT(?aw) AS ?n) WHERE { ?aw a :Awards ; p:hasFilms ?f . ?f a :Films ; p:title ?t ; p:Marketing_Expense ?me } GROUP BY ?f ?t ?me }
}
